sparql_query:
prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://conference#> 

SELECT (COUNT(*) AS ?cnt) 

	WHERE {?p rdf:type :Paper; 

		:is_submitted_at ?cnf . 

		?cnf rdf:type :Conference_volume }

prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://conference#> 

SELECT ?pNme ?absTxt 

	WHERE {?p rdf:type :Paper; 

		:has_an_abstract ?abs . 

		?abs rdf:type :Abstract }

prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://conference#> 

SELECT (COUNT(*) AS ?cnt) 

	WHERE {?pc rdf:type :Program_committee; 

		:was_a_program_committee_of ?cnf . 

		?cnf rdf:type :Conference_volume }

prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> 

prefix : <http://conference#> 

SELECT (COUNT(*) AS ?cnt) 

	WHERE {?c rdf:type :Program_committee; 

		:has_members ?p . 

		?p rdf:type :Person}
